<?php
declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';exigirPermiso('communications.view');$id=cmsId($_GET['id']??0);$pdo=obtenerConexion();$q=$pdo->prepare('SELECT h.*,u.nombre,u.apellido,u.correo correo_usuario FROM comunicacion_hilos h LEFT JOIN usuarios u ON u.id=h.usuario_id WHERE h.id=:id');$q->execute(['id'=>$id]);$h=$q->fetch();if(!$h){cmsFlash('error','Conversación no encontrada.');header('Location:index.php');exit;}$q=$pdo->prepare('SELECT m.*,u.nombre,u.apellido FROM comunicacion_mensajes m LEFT JOIN usuarios u ON u.id=m.autor_usuario_id WHERE m.hilo_id=:id ORDER BY m.created_at,id');$q->execute(['id'=>$id]);$mensajes=$q->fetchAll();cmsCabecera($h['asunto'],'comunicaciones/index.php','Conversación preservada dentro de Atenea.');?>
<div class="row"><div class="col-lg-8"><div class="card card-rounded"><div class="card-body"><?php foreach($mensajes as$m):?><div class="p-3 mb-3 rounded <?=$m['direccion']==='salida'?'bg-light border-start border-primary border-4':'border'?>"><strong><?=atenea_e(trim(($m['nombre']??'').' '.($m['apellido']??''))?:($m['autor_nombre']?:'Contacto'))?></strong><span class="badge bg-secondary float-end"><?=atenea_e($m['direccion'])?></span><p class="mt-2 mb-1" style="white-space:pre-wrap"><?=atenea_e($m['contenido'])?></p><small class="text-muted"><?=date('d/m/Y H:i',strtotime($m['created_at']))?><?php if($m['direccion']==='salida'):?> · <?=atenea_e($m['resultado_envio'])?><?php endif;?></small></div><?php endforeach;?></div></div></div><div class="col-lg-4"><div class="card card-rounded"><div class="card-body"><p><strong>Canal:</strong> <?=atenea_e($h['canal'])?><br><strong>Estado:</strong> <?=atenea_e($h['estado'])?><br><strong>Correo:</strong> <?=atenea_e($h['correo_usuario']?:$h['correo_contacto'])?></p><?php if(usuarioTienePermiso('communications.reply')):?><form method="post" action="responder.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="id" value="<?=$id?>"><label class="form-label">Respuesta</label><textarea class="form-control mb-3" name="mensaje" rows="7" maxlength="10000" required></textarea><button class="btn btn-primary w-100">Guardar y enviar</button></form><?php endif;?></div></div></div></div><?php cmsPie();
